function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error('parseDuration: invalid input');
  }

  // Bare integer: no unit suffix
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  const UNITS = [
    ['ms', 1],
    ['s', 1000],
    ['m', 60000],
    ['h', 3600000],
    ['d', 86400000],
  ];

  let total = 0;
  let remaining = str;

  while (remaining.length > 0) {
    const numMatch = remaining.match(/^(\d+)/);
    if (!numMatch) {
      throw new Error(`parseDuration: unexpected input at "${remaining}"`);
    }
    const value = parseInt(numMatch[1], 10);
    remaining = remaining.slice(numMatch[1].length);

    let matched = false;
    for (const [unit, ms] of UNITS) {
      if (remaining.startsWith(unit)) {
        total += value * ms;
        remaining = remaining.slice(unit.length);
        matched = true;
        break;
      }
    }

    if (!matched) {
      throw new Error(`parseDuration: unknown unit at "${remaining}"`);
    }
  }

  return total;
}

